solution_code:
#include <iostream>

int main()
{
    double mm {};
    std::cin >> mm;

    double meters     { mm * 1.0e-3 };
    double kilometers { mm * 1.0e-6 };

    std::cout << meters     << "\n";
    std::cout << kilometers << "\n";

    return 0;
}

